package com.enterprise.app.service;

import com.enterprise.app.model.AppUser;
import com.enterprise.app.repository.AppUserRepository;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

import java.util.List;
import java.util.Optional;

@Service
@Transactional
public class AppUserService {

    private final AppUserRepository appUserRepository;

    public AppUserService(AppUserRepository appUserRepository) {
        this.appUserRepository = appUserRepository;
    }

    public AppUser createUser(AppUser user) {
        return appUserRepository.save(user);
    }

    @Transactional(readOnly = true)
    public List<AppUser> getAllUsers() {
        return appUserRepository.findAll();
    }

    @Transactional(readOnly = true)
    public Optional<AppUser> getUserById(Long id) {
        return appUserRepository.findById(id);
    }

    @Transactional(readOnly = true)
    public Optional<AppUser> getUserByUsername(String username) {
        return appUserRepository.findByUsername(username);
    }

    public AppUser updateUser(Long id, AppUser updatedUser) {
        return appUserRepository.findById(id)
                .map(user -> {
                    user.setUsername(updatedUser.getUsername());
                    user.setEmail(updatedUser.getEmail());
                    user.setPassword(updatedUser.getPassword());
                    user.setActive(updatedUser.getActive());
                    return appUserRepository.save(user);
                })
                .orElseThrow(() -> new IllegalArgumentException("User not found with id: " + id));
    }

    public void deleteUser(Long id) {
        appUserRepository.deleteById(id);
    }
}

package com.enterprise.app.service;

import com.enterprise.app.model.AppUser;
import com.enterprise.app.model.TransactionRecord;
import com.enterprise.app.model.TransactionStatus;
import com.enterprise.app.repository.AppUserRepository;
import com.enterprise.app.repository.TransactionRecordRepository;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

import java.util.List;
import java.util.Optional;

@Service
@Transactional
public class TransactionRecordService {

    private final TransactionRecordRepository transactionRecordRepository;
    private final AppUserRepository appUserRepository;

    public TransactionRecordService(TransactionRecordRepository transactionRecordRepository,
                                    AppUserRepository appUserRepository) {
        this.transactionRecordRepository = transactionRecordRepository;
        this.appUserRepository = appUserRepository;
    }

    public TransactionRecord createTransaction(Long userId, TransactionRecord transactionRecord) {
        AppUser user = appUserRepository.findById(userId)
                .orElseThrow(() -> new IllegalArgumentException("User not found with id: " + userId));
        transactionRecord.setUser(user);
        return transactionRecordRepository.save(transactionRecord);
    }

    @Transactional(readOnly = true)
    public List<TransactionRecord> getAllTransactions() {
        return transactionRecordRepository.findAll();
    }

    @Transactional(readOnly = true)
    public Optional<TransactionRecord> getTransactionById(Long id) {
        return transactionRecordRepository.findById(id);
    }

    @Transactional(readOnly = true)
    public List<TransactionRecord> getTransactionsByUserId(Long userId) {
        return transactionRecordRepository.findByUserId(userId);
    }

    @Transactional(readOnly = true)
    public List<TransactionRecord> getTransactionsByStatus(TransactionStatus status) {
        return transactionRecordRepository.findByStatus(status);
    }

    public TransactionRecord updateTransactionStatus(Long transactionId, TransactionStatus status) {
        return transactionRecordRepository.findById(transactionId)
                .map(tx -> {
                    tx.setStatus(status);
                    return transactionRecordRepository.save(tx);
                })
                .orElseThrow(() -> new IllegalArgumentException("Transaction not found with id: " + transactionId));
    }

    public void deleteTransaction(Long transactionId) {
        transactionRecordRepository.deleteById(transactionId);
    }
}

package com.enterprise.app.controller;

import com.enterprise.app.model.AppUser;
import com.enterprise.app.service.AppUserService;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;

import java.util.List;

@RestController
@RequestMapping("/api/users")
public class AppUserController {

    private final AppUserService appUserService;

    public AppUserController(AppUserService appUserService) {
        this.appUserService = appUserService;
    }

    @PostMapping
    public ResponseEntity<AppUser> createUser(@RequestBody AppUser user) {
        return ResponseEntity.ok(appUserService.createUser(user));
    }

    @GetMapping
    public ResponseEntity<List<AppUser>> getAllUsers() {
        return ResponseEntity.ok(appUserService.getAllUsers());
    }

    @GetMapping("/{id}")
    public ResponseEntity<AppUser> getUserById(@PathVariable Long id) {
        return appUserService.getUserById(id)
                .map(ResponseEntity::ok)
                .orElse(ResponseEntity.notFound().build());
    }

    @PutMapping("/{id}")
    public ResponseEntity<AppUser> updateUser(@PathVariable Long id, @RequestBody AppUser user) {
        return ResponseEntity.ok(appUserService.updateUser(id, user));
    }

    @DeleteMapping("/{id}")
    public ResponseEntity<Void> deleteUser(@PathVariable Long id) {
        appUserService.deleteUser(id);
        return ResponseEntity.noContent().build();
    }
}

package com.enterprise.app.controller;

import com.enterprise.app.model.TransactionRecord;
import com.enterprise.app.model.TransactionStatus;
import com.enterprise.app.service.TransactionRecordService;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;

import java.util.List;

@RestController
@RequestMapping("/api/transactions")
public class TransactionRecordController {

    private final TransactionRecordService transactionRecordService;

    public TransactionRecordController(TransactionRecordService transactionRecordService) {
        this.transactionRecordService = transactionRecordService;
    }

    @PostMapping("/user/{userId}")
    public ResponseEntity<TransactionRecord> createTransaction(@PathVariable Long userId,
                                                               @RequestBody TransactionRecord transactionRecord) {
        return ResponseEntity.ok(transactionRecordService.createTransaction(userId, transactionRecord));
    }

    @GetMapping
    public ResponseEntity<List<TransactionRecord>> getAllTransactions() {
        return ResponseEntity.ok(transactionRecordService.getAllTransactions());
    }

    @GetMapping("/{id}")
    public ResponseEntity<TransactionRecord> getTransactionById(@PathVariable Long id) {
        return transactionRecordService.getTransactionById(id)
                .map(ResponseEntity::ok)
                .orElse(ResponseEntity.notFound().build());
    }

    @GetMapping("/user/{userId}")
    public ResponseEntity<List<TransactionRecord>> getTransactionsByUserId(@PathVariable Long userId) {
        return ResponseEntity.ok(transactionRecordService.getTransactionsByUserId(userId));
    }

    @GetMapping("/status/{status}")
    public ResponseEntity<List<TransactionRecord>> getTransactionsByStatus(@PathVariable TransactionStatus status) {
        return ResponseEntity.ok(transactionRecordService.getTransactionsByStatus(status));
    }

    @PatchMapping("/{id}/status")
    public ResponseEntity<TransactionRecord> updateTransactionStatus(@PathVariable Long id,
                                                                     @RequestParam TransactionStatus status) {
        return ResponseEntity.ok(transactionRecordService.updateTransactionStatus(id, status));
    }

    @DeleteMapping("/{id}")
    public ResponseEntity<Void> deleteTransaction(@PathVariable Long id) {
        transactionRecordService.deleteTransaction(id);
        return ResponseEntity.noContent().build();
    }
}

